chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"failc-selection",title:"Simplifier cette sélection avec FAILC",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener((t,e)=>{t.menuItemId==="failc-selection"&&t.selectionText&&(e!=null&&e.id)&&chrome.tabs.sendMessage(e.id,{type:"CONTEXT_SELECTION",selectionText:t.selectionText,tabId:e.id})});
